    phrases: [{tr: "Bugün geziyorum.", fr: "Aujourd’hui, je visite.", ipa: "bou-gun gué-zi-yo-roum"}, {tr: "Müzeye gidiyorum.", fr: "Je vais au musée.", ipa: "mu-zé-yé gui-di-yo-roum"}, {tr: "Kahve içiyorum.", fr: "Je bois un café.", ipa: "kah-vé i-tchi-yo-roum"}, {tr: "Yemek yiyorum.", fr: "Je mange.", ipa: "yé-mèk yi-yo-roum"}, {tr: "Sonra otele gidiyorum.", fr: "Ensuite, je vais à l’hôtel.", ipa: "son-ra o-té-lé gui-di-yo-roum"}, {tr: "Şimdi dinleniyorum.", fr: "Maintenant, je me repose.", ipa: "chim-di din-lé-ni-yo-roum"}],
